// src/pages/Internship.jsx
import React, { useEffect, useState } from "react";
import InternshipCard from "../components/InternshipCard";
import InternshipModal from "../components/InternshipModal";
import "./Internship.css";

export default function Internship({ currentUser }) {
  const [internships, setInternships] = useState([]);
  const [search, setSearch] = useState("");
  const [categoryFilter, setCategoryFilter] = useState("");
  const [selectedInternship, setSelectedInternship] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [appliedIds, setAppliedIds] = useState([]);

  useEffect(() => {
    fetch("/api/internships")
      .then((res) => res.json())
      .then((data) => setInternships(data));
  }, []);

  const handleApply = async (id) => {
    if (appliedIds.includes(id)) return;
    const res = await fetch(`/api/applications/apply/${id}`, {
      method: "POST",
      headers: { Authorization: localStorage.getItem("token") },
    });
    if (res.ok) setAppliedIds((prev) => [...prev, id]);
  };

  const filtered = internships.filter(
    (i) =>
      i.title.toLowerCase().includes(search.toLowerCase()) &&
      (!categoryFilter || i.category === categoryFilter)
  );

  const openModal = (internship = null) => {
    setSelectedInternship(internship);
    setShowModal(true);
  };

  return (
    <div className="internship-page">
      <div className="internship-header">
        <h2>Explore Internships</h2>

        <div className="internship-filters">
          <input
            type="text"
            placeholder="Search by title..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <select
            value={categoryFilter}
            onChange={(e) => setCategoryFilter(e.target.value)}
          >
            <option value="">All Categories</option>
            <option value="Web Dev">Web Dev</option>
            <option value="App Dev">App Dev</option>
            <option value="AI/ML">AI/ML</option>
          </select>

          {(currentUser?.role === "admin" || currentUser?.role === "hr") && (
            <button className="add-btn" onClick={() => openModal()}>
              + Add Internship
            </button>
          )}

          {currentUser?.role === "admin" && (
          <button className="add-btn" onClick={() => navigate("/applications")}>
            View Applications
          </button>
        )}

        </div>
      </div>

      <div className="internship-grid">
        {filtered.map((internship) => (
          <InternshipCard
            key={internship._id}
            internship={internship}
            currentUser={currentUser}
            onApply={handleApply}
            isApplied={appliedIds.includes(internship._id)}
          />
        ))}
      </div>

      {showModal && (
        <InternshipModal
          internship={selectedInternship}
          onClose={() => setShowModal(false)}
        />
      )}
    </div>
  );
}
